package main

import (
	"math"
)

func solve(nums []int64) int64 {
	var count int64
	n := len(nums)
	for i := 0; i < n; i++ {
		for j := i + 1; j < n; j++ {
			a := nums[i]
			b := nums[j]
			absA := math.Abs(float64(a))
			absB := math.Abs(float64(b))
			minAB := math.Min(absA, absB)
			maxAB := math.Max(absA, absB)
			diff := math.Abs(float64(a - b))
			sumAB := math.Abs(float64(a + b))
			minDiffSum := math.Min(diff, sumAB)
			maxDiffSum := math.Max(diff, sumAB)
			if minDiffSum <= minAB && maxDiffSum >= maxAB {
				count++
			}
		}
	}
	return count
}
